	CRM_COM_BUSINESS_TYPE varchar(50) NULL,
	CRM_COM_INDUSTRY_CAT varchar(200) NULL,
	CRM_COM_INDUSTRY_SUBCAT varchar(1000) NULL,
	CRM_COM_STAR_STATUS varchar(50) NULL,
